import os
import yaml
import re

base = "/tmp/openclaw-skills/skills/"

all_skills = []
for skill_name in os.listdir(base):
    skill_path = os.path.join(base, skill_name)
    md_path = os.path.join(skill_path, 'SKILL.md')
    if os.path.isdir(skill_path) and os.path.exists(md_path):
        with open(md_path, 'r', encoding='utf-8') as f:
            content = f.read()

        # Extract frontmatter
        front = re.search(r'^---\s*\n(.*?)\n---', content, re.DOTALL)
        if front:
            try:
                meta = yaml.safe_load(front.group(1))
            except:
                meta = {}
        else:
            meta = {}

        # Extract first paragraph of description
        desc = meta.get('description', '')
        if not desc:
            # Get first line after frontmatter
            lines = content.split('\n')
            for l in lines:
                if l.strip() and not l.startswith('#') and not l.startswith('---'):
                    desc = l.strip()
                    break

        all_skills.append({
            'name': skill_name,
            'desc': desc,
            'files': os.listdir(skill_path),
            'has_scripts': 'scripts' in os.listdir(skill_path)
        })

all_skills.sort(key=lambda x: x['name'])

print("## 📋 Tổng hợp toàn bộ 17 skills trong repo anthropics/skills\n")
print("| Skill Name | Mô tả | Scripts |")
print("|---|---|:---:|")
for s in all_skills:
    name = f"**{s['name']}**"
    desc = s['desc'][:110] + ('...' if len(s['desc'])>110 else '')
    has_scripts = '✅' if s['has_scripts'] else '❌'
    print(f"| {name:<25} | {desc:<100} | {has_scripts} |")

print(f"\n✅ Tổng: {len(all_skills)} skills.")
"}
